section.t:
All implementations MUST use RS256 (RSASSA-PKCS1-v1_5 using SHA-256
) as the signing algorithm.  No other signing algorithm is
permitted.

figure.artwork:
function IsSubset(parentScope, childScope):
    for each entry CE in childScope:
        childEntry = ParseScope(CE)
        if childEntry is invalid:
            return false
        covered = false
        for each entry PE in parentScope:
            parentEntry = ParseScope(PE)
            if parentEntry is invalid:
                continue
            if EntryCovers(parentEntry, childEntry):
                covered = true
                break
        if not covered:
            return false
    return true

function EntryCovers(parent, child):
    resourceOK = (parent.Resource == "*") OR
                 (parent.Resource == child.Resource)
    actionOK   = (parent.Action  == "*") OR
                 (parent.Action  == child.Action)
    return resourceOK AND actionOK

function Verify(tokenString, issuerPublicKey, revocationStore):

    // Step 1: Signature and expiry
    claims, err = RS256Parse(tokenString, issuerPublicKey)
    if err is not nil:
        return invalid("signature verification failed")

    // Step 2: Chain length invariant
    expectedLen = claims.att_depth + 1
    if len(claims.att_chain) != expectedLen:
        return invalid("chain length mismatch")

    // Step 3: Chain tail invariant
    if claims.att_chain[len(claims.att_chain) - 1] != claims.jti:
        return invalid("chain tail does not match jti")

    // Step 4: Revocation check
    if revocationStore.IsRevoked(claims.jti):
        return invalid("credential has been revoked")

    return valid(claims)

Revoke(X):
    targets = { jti | jti == X OR X in credentials[jti].att_chain }
    for each T in targets:
        revocations.insert(T, now, revokedBy)

figure.sourcecode:
CREATE TABLE IF NOT EXISTS credentials ( jti TEXT PRIMARY KEY, org_id TEXT NOT NULL, att_tid TEXT NOT NULL, att_pid TEXT, att_uid TEXT NOT NULL, agent_id TEXT NOT NULL, depth INTEGER NOT NULL DEFAULT 0, scope TEXT[] NOT NULL, chain TEXT[] NOT NULL, issued_at TIMESTAMPTZ NOT NULL, expires_at TIMESTAMPTZ NOT NULL );
CREATE INDEX IF NOT EXISTS idx_credentials_chain ON credentials USING GIN (chain);
CREATE TABLE IF NOT EXISTS revocations ( jti TEXT PRIMARY KEY, revoked_at TIMESTAMPTZ NOT NULL, revoked_by TEXT NOT NULL );
CREATE TABLE IF NOT EXISTS approvals ( id TEXT PRIMARY KEY, org_id TEXT NOT NULL, agent_id TEXT NOT NULL, att_tid TEXT NOT NULL, parent_token TEXT NOT NULL, intent TEXT NOT NULL, requested_scope TEXT[] NOT NULL, status TEXT NOT NULL DEFAULT 'pending', approved_by TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW(), resolved_at TIMESTAMPTZ );
CREATE TABLE IF NOT EXISTS audit_log ( id BIGSERIAL PRIMARY KEY, org_id TEXT NOT NULL, prev_hash TEXT NOT NULL, entry_hash TEXT NOT NULL, event_type TEXT NOT NULL, jti TEXT NOT NULL, att_tid TEXT NOT NULL, att_uid TEXT NOT NULL, agent_id TEXT NOT NULL, scope JSONB NOT NULL DEFAULT '[]', meta JSONB, idp_issuer TEXT, idp_subject TEXT, hitl_req TEXT, hitl_issuer TEXT, hitl_subject TEXT, created_at TIMESTAMPTZ NOT NULL DEFAULT NOW() );
CREATE OR REPLACE RULE audit_log_no_update AS ON UPDATE TO audit_log DO INSTEAD NOTHING; CREATE OR REPLACE RULE audit_log_no_delete AS ON DELETE TO audit_log DO INSTEAD NOTHING;
